const blocks = $input.all().map(item => item.json);
const config = {
  active_milestones: [],
  milestone_targets: {},
  cycle_milestone: null,
  show_next_cycle: true,
  trend_data_json: null,
  trend_data_block_id: null,
  slack_channel_id: '',
  report_settings: {}
};

let currentSection = '';
for (const block of blocks) {
  if (block.type === 'heading_2') {
    currentSection = block.heading_2?.text?.[0]?.plain_text || 
                     block.heading_2?.rich_text?.[0]?.plain_text || '';
    continue;
  }
  if (block.type === 'code') {
    const raw = block.code?.text?.[0]?.plain_text || 
                block.code?.rich_text?.[0]?.plain_text || '';
    const lines = raw.split('\n').map(l => l.replace(/^-\s*/, '').trim()).filter(Boolean);

    if (currentSection === 'Active Milestones') {
      lines.forEach(l => config.active_milestones.push(l));
    }
    else if (currentSection === 'Milestone Target Dates') {
      lines.forEach(l => {
        if (l.includes(':')) {
          const [name, ...rest] = l.split(':');
          config.milestone_targets[name.trim()] = rest.join(':').trim();
        }
      });
    }
    else if (currentSection === 'Cycle Tracking') {
      lines.forEach(l => {
        if (l.toLowerCase().startsWith('cycle milestone:')) {
          config.cycle_milestone = l.split(':')[1]?.trim();
        }
        if (l.toLowerCase().startsWith('show next cycle:')) {
          config.show_next_cycle = l.split(':')[1]?.trim().toLowerCase() === 'true';
        }
      });
    }
    else if (currentSection === 'Weekly Trend Data') {
      config.trend_data_json = raw;
      config.trend_data_block_id = block.id;
    }
    else if (currentSection === 'Slack Distribution') {
      lines.forEach(l => {
        if (l.toLowerCase().includes('leadership')) {
          config.slack_channel_id = l.split(':').slice(1).join(':').trim();
        }
      });
    }
    else if (currentSection === 'Report Settings') {
      lines.forEach(l => {
        if (l.includes(':')) {
          const [key, ...rest] = l.split(':');
          config.report_settings[key.trim()] = rest.join(':').trim();
        }
      });
    }
  }
}

config.active_milestones = [...new Set(config.active_milestones)];
return { json: config };

const blocks = $input.all().map(item => item.json);
const syncPage = $('Get many database pages').first().json;

// Highlights
let highlights = 'No highlights provided.';
if (syncPage?.properties?.Highlights?.rich_text?.length) {
  highlights = syncPage.properties.Highlights.rich_text.map(t => t.plain_text).join('').trim();
} else if (syncPage?.property_highlights) {
  highlights = typeof syncPage.property_highlights === 'string'
    ? syncPage.property_highlights
    : Array.isArray(syncPage.property_highlights)
      ? syncPage.property_highlights.map(t => t.plain_text || t).join('').trim()
      : 'No highlights provided.';
}

// Tomorrow's focus
let currentSection = '';
let tomorrowsFocus = '';

for (const block of blocks) {
  if (block.type === 'heading_1' || block.type === 'heading_2' || block.type === 'heading_3') {
    const text = (
      block[block.type]?.text?.[0]?.plain_text || 
      block[block.type]?.rich_text?.[0]?.plain_text || ''
    ).toLowerCase();
    if (text.includes("tomorrow's focus") || text.includes('section 7')) currentSection = 'focus';
    else currentSection = 'other';
    continue;
  }
  if (currentSection === 'focus' && block.type === 'bulleted_list_item') {
    const segments = block.bulleted_list_item?.text || 
                     block.bulleted_list_item?.rich_text || [];
    const content = segments.map(t => t.plain_text).join('').trim();
    if (content) tomorrowsFocus += '• ' + content + '\n';
  }
}

const syncDate = syncPage?.properties?.Date?.date?.start || syncPage?.property_date;
const syncTitle = syncPage?.properties?.['Sync Title']?.title?.[0]?.plain_text || syncPage?.name;
const syncPageId = syncPage?.id;

return {
  json: {
    highlights_content: highlights,
    tomorrows_focus: tomorrowsFocus.trim() || 'No focus items provided.',
    sync_date: syncDate,
    sync_title: syncTitle,
    sync_page_id: syncPageId
  }
};

const data = $input.first().json;
const allIssues = data.all_issues || [];
const activeMilestones = $('Parse Report Config1').first().json.active_milestones;

const filtered = allIssues.filter(issue => {
  const ms = issue.projectMilestone?.name;
  return ms && activeMilestones.includes(ms);
});

const mapped = filtered.map(issue => ({
  id: issue.identifier || issue.id,
  title: issue.title,
  status: issue.state?.name || 'Unknown',
  priority: issue.priority || 'No priority',
  assignee: issue.assignee?.name || issue.assignee?.displayName || null,
  labels: (issue.labels?.nodes || []).map(l => l.name),
  project: issue.project?.name || 'No project',
  projectMilestone: issue.projectMilestone?.name || 'No milestone',
  cycle: issue.cycle ? {
    id: issue.cycle.id,
    name: issue.cycle.name,
    number: issue.cycle.number,
    startsAt: issue.cycle.startsAt,
    endsAt: issue.cycle.endsAt
  } : null,
  dueDate: issue.dueDate || null,
  createdAt: issue.createdAt,
  updatedAt: issue.updatedAt
}));

return {
  json: {
    issues: mapped,
    issue_count: mapped.length,
    milestones_found: [...new Set(mapped.map(i => i.projectMilestone))]
  }
};

const config = $('Parse Report Config1').item.json;
const syncData = $('Parse Sync Page Content1').item.json;
const issueData = $('Filter Issues to Milestones1').item.json;

const promptContent = `Generate today's engineering dashboard report.

Report date: ${syncData.sync_date}

## Report Config

Active Milestones: ${JSON.stringify(config.active_milestones)}
Milestone Target Dates: ${JSON.stringify(config.milestone_targets)}
Cycle milestone: ${config.cycle_milestone || 'none configured'}
Show next cycle: ${config.show_next_cycle}
Report Settings: ${JSON.stringify(config.report_settings)}

## Weekly Trend Data
${config.trend_data_json || 'null — first run, compute metrics from issue createdAt dates'}

## Linear Issue Data (${issueData.issue_count} issues, pre-filtered to configured milestones)
${JSON.stringify(issueData.issues)}

## Sync Meeting Content

### Section 6: Daily Highlights
${syncData.highlights_content}

### Section 7: Tomorrow's Focus
${syncData.tomorrows_focus}`;

return {
  json: {
    prompt_content: promptContent,
    sync_date: syncData.sync_date,
    issue_count: issueData.issue_count
  }
};

