const raw = $input.first().json.text || '';
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Claude output is not valid JSON: ' + cleaned.substring(0, 200));
}

const syncDate = parsed.report_date || $('Parse Sync Page Content1').item.json.sync_date;
const dateFmt = syncDate ? syncDate.replace(/-/g, '') : 'UNKNOWN';

return {
  json: {
    ...parsed,
    slack_message: parsed.slack_summary || '',
    pdf_filename: `AccountOS_EngDashboard_${dateFmt}.pdf`,
    notion_title: `Product Report — ${syncDate}`,
    sync_page_id: $('Parse Sync Page Content1').item.json.sync_page_id,
    trend_data_block_id: $('Parse Report Config1').item.json.trend_data_block_id
  }
};

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const response = $input.first().json;
const issues = response.data?.issues?.nodes || [];
const pageInfo = response.data?.issues?.pageInfo;

return {
  json: {
    all_issues: issues,
    total_fetched: issues.length,
    hasNextPage: pageInfo?.hasNextPage,
    endCursor: pageInfo?.endCursor
  }
};

const { execSync } = require('child_process');
const fs = require('fs');

// Auto-install pptxgenjs if not present
if (!fs.existsSync('/tmp/node_modules/pptxgenjs')) {
  execSync('cd /tmp && npm install pptxgenjs 2>&1');
}

const d = $('Parse Claude Outputs1').item.json;
const reportDate = d.report_date || '';
const dateFmt = (reportDate).replace(/-/g, '');
const outputPath = `/tmp/AccountOS_EngDashboard_${dateFmt}.pptx`;

// Serialize data to pass into script
const dataJson = JSON.stringify(d).replace(/\\/g, '\\\\').replace(/`/g, '\\`');

const script = `
const PptxGenJS = require('/tmp/node_modules/pptxgenjs');
const fs = require('fs');

const d = JSON.parse(\`${dataJson}\`);

const C = {
  navy:     '0D1B2A', darkCard: '0A2540', rowAlt:   '112240',
  slate:    '334E68', slateL:   '94A3B8', white:    'FFFFFF',
  teal:     '0D9488', teal2:    '5EEAD4', mint:     '6EE7B7',
  green:    '22C55E', blue:     '3B82F6', purple:   'A855F7',
  amber:    'F59E0B', red:      'EF4444', cyan:     '22D3EE',
  orange:   'F97316', darkRed:  '7F1D1D', darkAmber:'78350F', darkGreen:'14532D',
};
const W = 10, H = 5.63, FONT = 'Calibri';
const pct = (n) => parseFloat((n || 0).toFixed(1));
const shortName = (s) => s ? s.replace(/@sprouts\\.ai/, '').replace(/@.*/, '') : '—';
const priColor = (p) => ({'Urg':'EF4444','Urgent':'EF4444','Hi':'F59E0B','High':'F59E0B','Med':'3B82F6','Medium':'3B82F6','Lo':'94A3B8','Low':'94A3B8','—':'94A3B8','No Priority':'94A3B8'})[p] || '94A3B8';

const pptx = new PptxGenJS();
pptx.layout = 'LAYOUT_16x9';
pptx.author = 'Sprouts AccountOS';

const addFooter = (slide, rightText) => {
  slide.addShape(pptx.ShapeType.rect, { x:0, y:H-0.22, w:W, h:0.22, fill:{color:C.teal} });
  slide.addText('Sprouts · Account OS · Engineering Dashboard', { x:0.15, y:H-0.21, w:5, h:0.2, fontSize:7, color:C.navy, fontFace:FONT, bold:true });
  slide.addText(rightText||'', { x:5, y:H-0.21, w:4.8, h:0.2, fontSize:7, color:C.navy, fontFace:FONT, align:'right' });
};
const sectionLabel = (slide, text, x, y) => {
  slide.addText(text, { x, y, w:9, h:0.2, fontSize:8, bold:true, color:C.teal2, fontFace:FONT, charSpacing:2 });
};

const cc = d.current_cycle || null;
const nc = d.next_cycle || null;
const milestones = d.milestones || [];
const insights = d.insights || { risks:[], actions:[], signals:[] };
const alerts = d.alerts || [];
const delivery = d.delivery || {};
const priorityBreakdown = d.priority_breakdown || [];
const labelBreakdown = d.label_breakdown || [];
const assigneeWorkload = d.assignee_workload || [];
const throughput7d = d.throughput_7d || [];
const trendWeeks = (d.trend && d.trend.weeks ? d.trend.weeks : []).slice(-8);

// ── SLIDE 1 ──────────────────────────────────────────────────
const s1 = pptx.addSlide();
s1.background = { color: C.navy };
s1.addShape(pptx.ShapeType.rect, { x:0, y:0, w:4.8, h:H, fill:{color:C.darkCard} });
s1.addText('Account OS', { x:0.4, y:1.3, w:4, h:0.55, fontSize:34, bold:true, color:C.white, fontFace:FONT });
s1.addText('Engineering Dashboard', { x:0.4, y:1.9, w:4, h:0.35, fontSize:20, color:C.slateL, fontFace:FONT });
s1.addShape(pptx.ShapeType.rect, { x:0.4, y:2.35, w:1.0, h:0.04, fill:{color:C.teal} });
s1.addText('Sprouts — Account OS Engineering', { x:0.4, y:2.5, w:4, h:0.22, fontSize:10, color:C.slateL, fontFace:FONT });
s1.addText(d.report_date + ' · Confidential', { x:0.4, y:2.75, w:4, h:0.2, fontSize:9, color:C.slate, fontFace:FONT });
const tags = [milestones.length + ' Active milestone' + (milestones.length !== 1 ? 's' : ''), 'Linear data', cc ? 'Cycle ' + cc.name + ' in flight' : 'No active cycle'];
tags.forEach(function(t, i) {
  s1.addShape(pptx.ShapeType.roundRect, { x:0.4+i*1.35, y:3.5, w:1.28, h:0.22, fill:{color:C.darkCard}, line:{color:C.slate,width:0.5}, rectRadius:0.05 });
  s1.addText(t, { x:0.4+i*1.35, y:3.5, w:1.28, h:0.22, fontSize:7, color:C.slateL, fontFace:FONT, align:'center' });
});
sectionLabel(s1, 'ACTIVE MILESTONES', 5.1, 0.4);
milestones.forEach(function(ms, i) {
  const cy = 0.75 + i * 1.55;
  const bColor = ms.go_live_status === 'On track' ? C.green : C.red;
  s1.addShape(pptx.ShapeType.roundRect, { x:5.1, y:cy, w:4.7, h:1.42, fill:{color:C.darkCard}, line:{color:C.slate,width:0.3}, rectRadius:0.08 });
  s1.addShape(pptx.ShapeType.rect, { x:5.1, y:cy, w:0.06, h:1.42, fill:{color:bColor} });
  s1.addText(ms.name, { x:5.25, y:cy+0.08, w:2.5, h:0.28, fontSize:14, bold:true, color:C.white, fontFace:FONT });
  const badgeBg = ms.go_live_status === 'On track' ? C.darkGreen : C.darkRed;
  const badgeText = ms.go_live_status === 'On track' ? C.mint : 'FCA5A5';
  s1.addShape(pptx.ShapeType.roundRect, { x:7.6, y:cy+0.1, w:2.1, h:0.22, fill:{color:badgeBg}, rectRadius:0.04 });
  s1.addText(ms.go_live_status, { x:7.6, y:cy+0.1, w:2.1, h:0.22, fontSize:8, bold:true, color:badgeText, fontFace:FONT, align:'center' });
  s1.addText('Target: ' + ms.target_date + '  ·  ' + ms.completion_pct + '%  ·  ' + ms.total + ' issues', { x:5.25, y:cy+0.38, w:4.4, h:0.18, fontSize:9, color:C.slateL, fontFace:FONT });
  s1.addShape(pptx.ShapeType.rect, { x:5.25, y:cy+0.6, w:4.4, h:0.1, fill:{color:C.rowAlt} });
  if (ms.completion_pct > 0) s1.addShape(pptx.ShapeType.rect, { x:5.25, y:cy+0.6, w:4.4*Math.min(ms.completion_pct/100,1), h:0.1, fill:{color:bColor} });
  [{v:ms.rfp,l:'Ready for Prod',c:C.cyan},{v:ms.in_qa,l:'In QA',c:C.purple},{v:ms.in_progress,l:'In Progress',c:C.blue},{v:ms.todo,l:'Todo',c:C.amber}].forEach(function(st, j) {
    const sx = 5.25 + j * 1.1;
    s1.addText(String(st.v), { x:sx, y:cy+0.82, w:1.0, h:0.3, fontSize:17, bold:true, color:st.c, fontFace:FONT, align:'center' });
    s1.addText(st.l, { x:sx, y:cy+1.13, w:1.0, h:0.16, fontSize:7, color:C.slateL, fontFace:FONT, align:'center' });
  });
});
addFooter(s1, 'Title · ' + d.report_date);

// ── SLIDE 2 ──────────────────────────────────────────────────
const s2 = pptx.addSlide();
s2.background = { color: C.navy };
s2.addText('Executive Summary', { x:0.3, y:0.12, w:7, h:0.35, fontSize:18, bold:true, color:C.white, fontFace:FONT });
s2.addText(d.report_date, { x:7, y:0.12, w:2.7, h:0.35, fontSize:10, color:C.slateL, fontFace:FONT, align:'right' });
[
  { title:'CRITICAL RISKS', items:insights.risks, bg:C.darkRed, dot:C.red, textColor:'FCA5A5' },
  { title:'IMMEDIATE ACTIONS', items:insights.actions, bg:C.darkAmber, dot:C.amber, textColor:'FCD34D' },
  { title:'POSITIVE SIGNALS', items:insights.signals, bg:C.darkGreen, dot:C.green, textColor:'86EFAC' },
].forEach(function(col, i) {
  const cx = 0.3 + i * 3.23;
  s2.addShape(pptx.ShapeType.rect, { x:cx, y:0.6, w:3.1, h:0.28, fill:{color:col.bg} });
  s2.addText(col.title, { x:cx+0.1, y:0.6, w:3.0, h:0.28, fontSize:9, bold:true, color:col.textColor, fontFace:FONT });
  s2.addShape(pptx.ShapeType.rect, { x:cx, y:0.88, w:3.1, h:4.3, fill:{color:C.darkCard} });
  col.items.slice(0,4).forEach(function(item, j) {
    const ty = 0.96 + j * 0.88;
    s2.addShape(pptx.ShapeType.ellipse, { x:cx+0.12, y:ty+0.04, w:0.1, h:0.1, fill:{color:col.dot} });
    s2.addText(item.text, { x:cx+0.28, y:ty, w:2.75, h:0.82, fontSize:9.5, color:'CBD5E1', fontFace:FONT, wrap:true, valign:'top' });
  });
});
addFooter(s2, 'Executive Summary · ' + d.report_date);

// ── SLIDE 3 ──────────────────────────────────────────────────
const s3 = pptx.addSlide();
s3.background = { color: C.navy };
s3.addText('Milestone Progress Overview', { x:0.3, y:0.12, w:7, h:0.35, fontSize:18, bold:true, color:C.white, fontFace:FONT });
s3.addText(d.report_date, { x:7, y:0.12, w:2.7, h:0.35, fontSize:10, color:C.slateL, fontFace:FONT, align:'right' });
sectionLabel(s3, 'STATUS BREAKDOWN — ALL ACTIVE MILESTONES', 0.3, 0.6);
const barColors = [C.green, C.cyan, C.purple, C.blue, C.amber, C.slateL];
const barLabels = ['Closed','Ready for Prod','In QA','In Progress','Todo','Canceled/Dup'];
const barH = 0.32, barGap = 0.18;
let barsEndY = 0.85;
milestones.forEach(function(ms, i) {
  const by = barsEndY + i * (barH + barGap);
  const segments = [ms.closed, ms.rfp, ms.in_qa, ms.in_progress, ms.todo, ms.canceled_dup];
  const total = ms.total || 1;
  s3.addText(ms.name, { x:0.3, y:by-0.18, w:9, h:0.18, fontSize:9, bold:true, color:C.teal2, fontFace:FONT });
  let offsetX = 0.3;
  segments.forEach(function(seg, j) {
    const segW = (seg / total) * 9.0;
    if (segW > 0.01) {
      s3.addShape(pptx.ShapeType.rect, { x:offsetX, y:by, w:segW, h:barH, fill:{color:barColors[j]} });
      if (segW > 0.3) s3.addText(String(seg), { x:offsetX, y:by, w:segW, h:barH, fontSize:8, color:C.navy, fontFace:FONT, align:'center', valign:'middle', bold:true });
      offsetX += segW;
    }
  });
  barsEndY = by;
});
barsEndY += barH + 0.1;
barLabels.forEach(function(lbl, i) {
  const lx = 0.3 + i * 1.55;
  s3.addShape(pptx.ShapeType.rect, { x:lx, y:barsEndY+0.05, w:0.14, h:0.14, fill:{color:barColors[i]} });
  s3.addText(lbl, { x:lx+0.18, y:barsEndY+0.04, w:1.3, h:0.16, fontSize:8, color:C.slateL, fontFace:FONT });
});
barsEndY += 0.35;
const ptY = barsEndY + 0.25;
sectionLabel(s3, 'OPEN BY PRIORITY', 0.3, ptY);
const ptHeaders = ['Priority','Open','In QA','In Prog','In Review','Todo'];
const ptColW = [1.6, 0.9, 0.9, 0.9, 0.9, 0.9];
const ptRowH = 0.28;
const ptStartY = ptY + 0.22;
let ptX = 0.3;
ptHeaders.forEach(function(h, i) {
  s3.addShape(pptx.ShapeType.rect, { x:ptX, y:ptStartY, w:ptColW[i], h:ptRowH, fill:{color:C.darkCard} });
  s3.addText(h, { x:ptX+0.05, y:ptStartY, w:ptColW[i], h:ptRowH, fontSize:9, bold:true, color:C.teal2, fontFace:FONT, valign:'middle' });
  ptX += ptColW[i];
});
priorityBreakdown.forEach(function(row, ri) {
  const ry = ptStartY + (ri+1) * ptRowH;
  const isTotal = row.priority === 'TOTAL';
  const rowBg = isTotal ? C.darkCard : (ri % 2 === 0 ? C.navy : C.rowAlt);
  ptX = 0.3;
  [row.priority, row.open, row.in_qa, row.in_progress, row.in_review, row.todo].forEach(function(cell, ci) {
    s3.addShape(pptx.ShapeType.rect, { x:ptX, y:ry, w:ptColW[ci], h:ptRowH, fill:{color:rowBg} });
    const cellColor = isTotal ? C.mint : (ci === 0 ? priColor(String(cell)) : C.white);
    s3.addText(String(cell), { x:ptX+0.05, y:ry, w:ptColW[ci], h:ptRowH, fontSize:9, color:cellColor, fontFace:FONT, valign:'middle', bold:isTotal });
    ptX += ptColW[ci];
  });
});
addFooter(s3, 'Milestone Progress · ' + d.report_date);

// ── SLIDE 4 ──────────────────────────────────────────────────
const s4 = pptx.addSlide();
s4.background = { color: C.navy };
s4.addText('Cycle Focus', { x:0.3, y:0.12, w:7, h:0.35, fontSize:18, bold:true, color:C.white, fontFace:FONT });
s4.addText('Current cycle · ' + d.report_date, { x:7, y:0.12, w:2.7, h:0.35, fontSize:10, color:C.slateL, fontFace:FONT, align:'right' });
if (!cc) {
  s4.addShape(pptx.ShapeType.roundRect, { x:2, y:1.5, w:6, h:1.5, fill:{color:C.darkCard}, rectRadius:0.1 });
  s4.addText('No active cycle for ' + (d.cycle_milestone || 'configured milestone'), { x:2, y:1.7, w:6, h:0.4, fontSize:14, color:C.slateL, fontFace:FONT, align:'center' });
  if (nc) s4.addText('Next: ' + nc.name + ' starts ' + (nc.starts_at||'').split('T')[0], { x:2, y:2.15, w:6, h:0.3, fontSize:11, color:C.teal2, fontFace:FONT, align:'center' });
} else {
  const cycleColor = cc.health_color === 'red' ? C.red : cc.health_color === 'amber' ? C.amber : C.teal;
  sectionLabel(s4, 'CURRENT CYCLE', 0.3, 0.55);
  s4.addShape(pptx.ShapeType.roundRect, { x:0.3, y:0.75, w:9.4, h:1.0, fill:{color:C.darkCard}, rectRadius:0.08 });
  s4.addShape(pptx.ShapeType.rect, { x:0.3, y:0.75, w:0.07, h:1.0, fill:{color:C.teal} });
